import * as class_variance_authority_types from 'class-variance-authority/types';
import * as react_jsx_runtime from 'react/jsx-runtime';
import { Label } from './label.js';
import { VariantProps } from 'class-variance-authority';
import 'react';
import 'radix-ui';

/**
 * A semantic `<fieldset>` wrapper that groups related form fields together.
 *
 * ### Example Usage
 *
 * ```tsx
 * <FieldSet>
 *   <FieldLegend>Personal Information</FieldLegend>
 *   <FieldGroup>
 *     <Field>
 *       <FieldLabel>Name</FieldLabel>
 *       <Input placeholder="Enter your name" />
 *     </Field>
 *   </FieldGroup>
 * </FieldSet>
 * ```
 */
declare function FieldSet({ className, ...props }: React.ComponentProps<'fieldset'>): react_jsx_runtime.JSX.Element;
/**
 * A `<legend>` element for a `FieldSet`, providing a heading for the group of fields.
 *
 * ### Component Props
 *
 * | Prop       | Type                     | Default    |
 * | :--------- | :----------------------- | :--------- |
 * | _variant_  | `"legend" \| "label"`    | `"legend"` |
 *
 *
 * ### Example Usage
 *
 * **Legend**
 * ```tsx
 * <FieldLegend>Personal Information</FieldLegend>
 * ```
 *
 * **Label**
 * ```tsx
 * <FieldLegend variant="label">Account Settings</FieldLegend>
 * ```
 */
declare function FieldLegend({ className, variant, ...props }: React.ComponentProps<'legend'> & {
    variant?: 'legend' | 'label';
}): react_jsx_runtime.JSX.Element;
/**
 * A container that groups multiple `Field` components with consistent spacing.
 *
 * ### Example Usage
 *
 * ```tsx
 * <FieldGroup>
 *   <Field>
 *     <FieldLabel>First Name</FieldLabel>
 *     <Input />
 *   </Field>
 *   <Field>
 *     <FieldLabel>Last Name</FieldLabel>
 *     <Input />
 *   </Field>
 * </FieldGroup>
 * ```
 */
declare function FieldGroup({ className, ...props }: React.ComponentProps<'div'>): react_jsx_runtime.JSX.Element;
declare const fieldVariants: (props?: ({
    orientation?: "horizontal" | "vertical" | "responsive" | null | undefined;
} & class_variance_authority_types.ClassProp) | undefined) => string;
/**
 * A form field wrapper that arranges a label, input, description, and error message with proper layout.
 *
 * ### Component Props
 *
 * | Prop            | Type                                          | Default      |
 * | :-------------- | :-------------------------------------------- | :----------- |
 * | _orientation_   | `"vertical" \| "horizontal" \| "responsive"`  | `"vertical"` |
 *
 *
 * ### Example Usage
 *
 * **Vertical**
 * ```tsx
 * <Field>
 *   <FieldLabel>Email</FieldLabel>
 *   <FieldContent>
 *     <Input type="email" placeholder="you@example.com" />
 *     <FieldDescription>We will never share your email.</FieldDescription>
 *   </FieldContent>
 * </Field>
 * ```
 *
 * **Horizontal**
 * ```tsx
 * <Field orientation="horizontal">
 *   <FieldLabel>Name</FieldLabel>
 *   <FieldContent>
 *     <Input placeholder="Enter your name" />
 *   </FieldContent>
 * </Field>
 * ```
 *
 * **Responsive**
 * ```tsx
 * <Field orientation="responsive">
 *   <FieldLabel>Bio</FieldLabel>
 *   <FieldContent>
 *     <Textarea placeholder="Tell us about yourself" />
 *   </FieldContent>
 * </Field>
 * ```
 *
 * ### Accessibility (WCAG 2.2 AA)
 *
 * @wcag 1.3.1 Info and Relationships — FieldLabel associates with input via htmlFor/id.
 * @wcag 3.3.1 Error Identification — FieldError uses role="alert" to announce errors to screen readers.
 * @wcag 3.3.2 Labels or Instructions — FieldLabel and FieldDescription provide context for the input.
 * @wcag 4.1.3 Status Messages — error messages announced via role="alert" without receiving focus.
 */
declare function Field({ className, orientation, ...props }: React.ComponentProps<'fieldset'> & VariantProps<typeof fieldVariants>): react_jsx_runtime.JSX.Element;
/**
 * A container for a field's input, description, and error message content.
 *
 * ### Example Usage
 *
 * ```tsx
 * <FieldContent>
 *   <Input />
 *   <FieldDescription>Helper text goes here.</FieldDescription>
 * </FieldContent>
 * ```
 */
declare function FieldContent({ className, ...props }: React.ComponentProps<'div'>): react_jsx_runtime.JSX.Element;
/**
 * A label element for a form field. Wraps the `Label` component with field-specific styling.
 *
 * ### Example Usage
 *
 * ```tsx
 * <FieldLabel htmlFor="name">Full Name</FieldLabel>
 * ```
 */
declare function FieldLabel({ className, ...props }: React.ComponentProps<typeof Label>): react_jsx_runtime.JSX.Element;
/**
 * A non-label title element for a form field, useful when a `<label>` is not needed.
 *
 * ### Example Usage
 *
 * ```tsx
 * <FieldTitle>Notification Preferences</FieldTitle>
 * ```
 */
declare function FieldTitle({ className, ...props }: React.ComponentProps<'div'>): react_jsx_runtime.JSX.Element;
/**
 * A helper text element that provides additional context or instructions for a form field.
 *
 * ### Example Usage
 *
 * ```tsx
 * <FieldDescription>
 *   Must be at least 8 characters long.
 * </FieldDescription>
 * ```
 */
declare function FieldDescription({ className, ...props }: React.ComponentProps<'p'>): react_jsx_runtime.JSX.Element;
/**
 * A visual separator between fields, optionally displaying text content in the center.
 *
 * ### Example Usage
 *
 * ```tsx
 * <Field>...</Field>
 * <FieldSeparator>or</FieldSeparator>
 * <Field>...</Field>
 * ```
 */
declare function FieldSeparator({ children, className, ...props }: React.ComponentProps<'div'> & {
    children?: React.ReactNode;
}): react_jsx_runtime.JSX.Element;
/**
 * Displays validation error messages for a form field. Supports both direct children and an `errors` array.
 *
 * ### Component Props
 *
 * | Prop      | Type                                        | Default |
 * | :-------- | :------------------------------------------ | :------ |
 * | _errors_  | `Array<{ message?: string } \| undefined>`  | -       |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <FieldError>This field is required.</FieldError>
 *
 * <FieldError errors={[{ message: "Too short" }, { message: "Invalid format" }]} />
 * ```
 *
 * ```tsx
 * <Field>
 *   <FieldLabel htmlFor="email">Email</FieldLabel>
 *   <Input id="email" aria-describedby="email-error" aria-invalid={hasError} />
 *   <FieldError id="email-error" errors={errors} />
 * </Field>
 * ```
 *
 * Pass `id` and set `aria-describedby={id}` on the associated input for screen reader error announcement.
 */
declare function FieldError({ className, children, errors, ...props }: React.ComponentProps<'div'> & {
    errors?: Array<{
        message?: string;
    } | undefined>;
}): react_jsx_runtime.JSX.Element | null;

export { Field, FieldContent, FieldDescription, FieldError, FieldGroup, FieldLabel, FieldLegend, FieldSeparator, FieldSet, FieldTitle };
